Create the `FeatureCard` component used in both the catalog grid and the homepage teaser section.

**File to create:** `apps/site/src/layers/features/marketing/ui/FeatureCard.tsx`

**Implementation:**

```typescript
import Link from 'next/link';
import { ArrowRight } from 'lucide-react';
import type { Feature } from '../lib/features';
import { CATEGORY_LABELS } from '../lib/features';

interface FeatureCardProps {
  feature: Feature;
}

/**
 * Compact feature card for use in catalog grids.
 * Links to /features/[slug].
 */
export function FeatureCard({ feature }: FeatureCardProps) {
  const statusStyles: Record<string, string> = {
    ga: 'bg-emerald-100/60 text-emerald-900',
    beta: 'bg-amber-100/60 text-amber-900',
    'coming-soon': 'bg-warm-gray/10 text-warm-gray-light',
  };
  const statusLabels: Record<string, string> = {
    ga: 'Available',
    beta: 'Beta',
    'coming-soon': 'Coming Soon',
  };

  return (
    <Link
      href={`/features/${feature.slug}`}
      className="border-warm-gray-light/20 hover:border-warm-gray-light/50 hover:shadow-sm transition-smooth group flex flex-col rounded-xl border bg-white/40 p-5"
    >
      <div className="mb-3 flex items-center gap-2">
        <span className="text-warm-gray-light border-warm-gray-light/30 rounded-full border px-2 py-0.5 font-mono text-xs">
          {CATEGORY_LABELS[feature.category]}
        </span>
        <span
          className={`rounded-full px-2 py-0.5 font-mono text-xs ${statusStyles[feature.status] ?? ''}`}
        >
          {statusLabels[feature.status] ?? feature.status}
        </span>
      </div>

      <h3 className="text-charcoal group-hover:text-brand-orange transition-smooth mb-1 font-mono text-base font-semibold">
        {feature.name}
      </h3>
      <p className="text-warm-gray mb-4 flex-1 text-sm leading-relaxed">{feature.tagline}</p>

      <div className="text-warm-gray-light group-hover:text-brand-orange transition-smooth flex items-center gap-1 font-mono text-xs">
        Learn more <ArrowRight size={10} />
      </div>
    </Link>
  );
}
```

**Key design details:**
- The entire card is a `<Link>` wrapping the content — the whole card is clickable
- Uses `group` / `group-hover` pattern for hover state propagation
- Status badge colors: ga = emerald, beta = amber, coming-soon = warm-gray
- Status labels: ga = 'Available', beta = 'Beta', coming-soon = 'Coming Soon'
- Category label comes from `CATEGORY_LABELS` record
- Uses `transition-smooth` utility (existing in the design system)
- `flex-1` on the tagline paragraph ensures consistent card heights in a grid
- Font is `font-mono` for headings (matches DorkOS brand voice)

**Acceptance Criteria:**
- [ ] Component renders feature name, tagline, category badge, and status badge
- [ ] Links to `/features/{slug}`
- [ ] All 3 status variants render correct label and color
- [ ] TSDoc on exported component
- [ ] Compiles with zero TypeScript errors

Create the `/features` catalog index page with server-rendered category tab filtering.

**File to create:** `apps/site/src/app/(marketing)/features/page.tsx`

**Implementation:**

This is a server component. It reads `?category=` from `searchParams` to filter features. No client JavaScript is used for filtering — each category tab is a `<Link>` that produces a full server request.

```typescript
import type { Metadata } from 'next/types';
import Link from 'next/link';
import { siteConfig } from '@/config/site';
import { features, CATEGORY_LABELS, type FeatureCategory } from '@/layers/features/marketing';
import { FeatureCard } from '@/layers/features/marketing';

export const metadata: Metadata = {
  title: 'Features — DorkOS',
  description:
    'The complete DorkOS feature catalog — scheduling, messaging, agent discovery, and more. Built for developers who ship.',
  alternates: { canonical: '/features' },
  openGraph: {
    title: 'Features — DorkOS',
    description: 'The complete DorkOS feature catalog.',
    url: '/features',
    siteName: siteConfig.name,
  },
};

const VALID_CATEGORIES = Object.keys(CATEGORY_LABELS) as FeatureCategory[];

export default async function FeaturesPage(props: { searchParams: Promise<Record<string, string | string[] | undefined>> }) {
  const searchParams = await props.searchParams;
  const rawCategory = searchParams['category'];
  const activeCategory =
    typeof rawCategory === 'string' && VALID_CATEGORIES.includes(rawCategory as FeatureCategory)
      ? (rawCategory as FeatureCategory)
      : null;

  const filteredFeatures = activeCategory
    ? features.filter((f) => f.category === activeCategory)
    : features;

  // Sort within each category by sortOrder, then insertion order
  const sortedFeatures = [...filteredFeatures].sort((a, b) => {
    if (a.category !== b.category) return 0;
    return (a.sortOrder ?? 999) - (b.sortOrder ?? 999);
  });

  return (
    <div className="mx-auto max-w-6xl px-6 pt-32 pb-24">
      <header className="mb-12">
        <h1 className="text-charcoal font-mono text-4xl font-bold tracking-tight">Features</h1>
        <p className="text-warm-gray mt-3 max-w-2xl text-lg">
          Everything DorkOS does — scheduling, messaging, discovery, and control.
        </p>
      </header>

      {/* Category tab strip — pure links, no JS */}
      <nav className="mb-10 flex flex-wrap gap-2" aria-label="Filter by category">
        <CategoryTab href="/features" active={activeCategory === null} label="All" />
        {VALID_CATEGORIES.map((cat) => (
          <CategoryTab
            key={cat}
            href={`/features?category=${cat}`}
            active={activeCategory === cat}
            label={CATEGORY_LABELS[cat]}
          />
        ))}
      </nav>

      {sortedFeatures.length === 0 ? (
        <p className="text-warm-gray-light text-sm">No features in this category yet.</p>
      ) : (
        <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {sortedFeatures.map((feature) => (
            <FeatureCard key={feature.slug} feature={feature} />
          ))}
        </div>
      )}
    </div>
  );
}

function CategoryTab({ href, active, label }: { href: string; active: boolean; label: string }) {
  return (
    <Link
      href={href}
      className={`rounded-full px-4 py-1.5 font-mono text-xs tracking-[0.04em] transition-colors ${
        active
          ? 'bg-charcoal text-cream-primary'
          : 'border-warm-gray-light/30 text-warm-gray hover:text-charcoal border'
      }`}
    >
      {label}
    </Link>
  );
}
```

**Key constraints:**
- `searchParams` is `Promise<...>` in Next.js 15+/16 — must be awaited
- `CategoryTab` uses `<Link>` not `<button>` — each tab is a navigable, indexable URL
- Invalid `?category=` values silently fall back to 'All' (no error, no redirect)
- The `(marketing)` route group is a Next.js group folder — the page inherits the marketing layout
- Sorting is stable within categories by `sortOrder`; cross-category order preserved from array

**Acceptance Criteria:**
- [ ] `/features` renders all 13 features in a responsive 3-column grid
- [ ] `/features?category=relay` shows only Relay features
- [ ] `/features?category=invalid` shows all features (silent fallback)
- [ ] Category tabs are `<Link>` elements with correct href values
- [ ] Active tab has distinct visual style (`bg-charcoal text-cream-primary`)
- [ ] Metadata includes title, description, canonical, and OG tags
- [ ] Page compiles as a server component (no `'use client'`)

Create the individual feature page with static generation, JSON-LD structured data, and full feature detail layout.

**File to create:** `apps/site/src/app/(marketing)/features/[slug]/page.tsx`

**Implementation:**

The page uses `generateStaticParams()` to pre-render all feature slugs at build time and `generateMetadata()` for per-feature SEO metadata.

```typescript
import type { Metadata } from 'next';
import Link from 'next/link';
import { notFound } from 'next/navigation';
import { ArrowLeft, ArrowRight, ExternalLink, CheckCircle } from 'lucide-react';
import { features, CATEGORY_LABELS } from '@/layers/features/marketing';
import { siteConfig } from '@/config/site';

export function generateStaticParams() {
  return features.map((f) => ({ slug: f.slug }));
}

export async function generateMetadata(props: {
  params: Promise<{ slug: string }>;
}): Promise<Metadata> {
  const params = await props.params;
  const feature = features.find((f) => f.slug === params.slug);
  if (!feature) notFound();

  return {
    title: `${feature.name} — DorkOS`,
    description: feature.description,
    openGraph: {
      title: `${feature.name} — DorkOS`,
      description: feature.description,
      url: `/features/${feature.slug}`,
      siteName: siteConfig.name,
      type: 'website',
    },
    alternates: {
      canonical: `/features/${feature.slug}`,
    },
  };
}
```

The page component renders:
1. **BreadcrumbList JSON-LD** — Home > Features > Feature Name (3-level)
2. **SoftwareApplication JSON-LD** — with `featureList` from benefits array, `applicationCategory: 'DeveloperApplication'`, free pricing
3. **Back link** — arrow + "Features" linking to `/features`
4. **Category badge** — using `CATEGORY_LABELS`
5. **Status badge** — ga='Available' (emerald), beta='Beta' (amber), coming-soon='Coming Soon' (gray)
6. **Feature name** (h1), **tagline** (xl text), **description** (base text)
7. **Benefits checklist** — CheckCircle icon (brand-orange) + benefit text
8. **Screenshot** (if `media.screenshot` present) — `<img>` with alt text
9. **Docs link** (if `docsUrl` present) — ExternalLink icon
10. **Related features** — pill-style links with ArrowRight icon

JSON-LD XSS prevention: all JSON-LD blocks use `.replace(/</g, '\\u003c')` in `dangerouslySetInnerHTML`.

The full component code is in the spec Section 3 — implement it exactly as specified there, including the `StatusBadge` helper component.

**Key constraints:**
- `params` is `Promise<{ slug: string }>` in Next.js 15+/16 — must be awaited
- `generateStaticParams` returns all feature slugs for static generation
- `notFound()` called for unknown slugs
- `relatedFeatures` resolved by looking up slugs in the `features` array, filtered with `.filter(Boolean)` to handle missing refs
- JSON-LD uses `siteConfig.url` for absolute URLs

**Acceptance Criteria:**
- [ ] `/features/pulse-scheduler` renders the Pulse Scheduler feature page with all sections
- [ ] `/features/nonexistent` returns 404
- [ ] BreadcrumbList JSON-LD is present in page source
- [ ] SoftwareApplication JSON-LD includes `featureList` with benefits
- [ ] Back link points to `/features`
- [ ] Related features link to their respective `/features/[slug]` pages
- [ ] Docs link points to correct `docsUrl`
- [ ] Status badges show correct label and color for ga, beta, coming-soon
- [ ] Page compiles as a server component

Create the dynamic Open Graph image generation route for individual feature pages.

**File to create:** `apps/site/src/app/(marketing)/features/[slug]/opengraph-image.tsx`

**Implementation:**

```typescript
import { ImageResponse } from 'next/og';
import { features } from '@/layers/features/marketing';
import { siteConfig } from '@/config/site';

export const alt = 'DorkOS Feature';
export const size = { width: 1200, height: 630 };
export const contentType = 'image/png';

export default async function Image(props: { params: Promise<{ slug: string }> }) {
  const params = await props.params;
  const feature = features.find((f) => f.slug === params.slug);

  return new ImageResponse(
    (
      <div
        style={{
          background: '#F5F0E8',
          width: '100%',
          height: '100%',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          padding: '80px',
        }}
      >
        <div style={{ fontSize: 16, color: '#9B8E7E', fontFamily: 'monospace', marginBottom: 24 }}>
          {siteConfig.name}
        </div>
        <div
          style={{ fontSize: 56, fontWeight: 700, color: '#1A1714', fontFamily: 'monospace', lineHeight: 1.1 }}
        >
          {feature?.name ?? 'Feature'}
        </div>
        <div style={{ fontSize: 24, color: '#6B5E4E', marginTop: 20, maxWidth: 800 }}>
          {feature?.tagline}
        </div>
      </div>
    ),
    size
  );
}
```

**Design details:**
- Background color `#F5F0E8` is the DorkOS cream-primary color
- Title color `#1A1714` is charcoal
- Subtitle color `#6B5E4E` is warm-gray
- Site name color `#9B8E7E` is warm-gray-light
- Uses monospace font family to match DorkOS brand
- Image dimensions: 1200x630 (standard OG image size)
- Graceful fallback: shows 'Feature' if slug doesn't match

**Acceptance Criteria:**
- [ ] OG image generates for each feature slug
- [ ] Image shows feature name and tagline
- [ ] Uses DorkOS brand colors (cream background, charcoal text)
- [ ] File exports `alt`, `size`, and `contentType` constants
- [ ] `params` is awaited (Next.js 15+/16 async params)

Write comprehensive data integrity tests that validate all constraints on the features array.

**File to create:** `apps/site/src/layers/features/marketing/lib/__tests__/features.test.ts`

```typescript
import { describe, it, expect } from 'vitest';
import { features, CATEGORY_LABELS, type FeatureCategory } from '../features';

describe('features catalog data integrity', () => {
  it('all slugs are unique', () => {
    const slugs = features.map((f) => f.slug);
    const unique = new Set(slugs);
    expect(unique.size).toBe(slugs.length);
  });

  it('all relatedFeatures references resolve to valid slugs', () => {
    const allSlugs = new Set(features.map((f) => f.slug));
    for (const feature of features) {
      for (const ref of feature.relatedFeatures ?? []) {
        expect(allSlugs.has(ref)).toBe(true);
      }
    }
  });

  it('all taglines are ≤80 chars', () => {
    for (const feature of features) {
      expect(feature.tagline.length).toBeLessThanOrEqual(80);
    }
  });

  it('all descriptions are 120-160 chars', () => {
    for (const feature of features) {
      expect(feature.description.length).toBeGreaterThanOrEqual(120);
      expect(feature.description.length).toBeLessThanOrEqual(160);
    }
  });

  it('each feature has 3-5 benefits', () => {
    for (const feature of features) {
      expect(feature.benefits.length).toBeGreaterThanOrEqual(3);
      expect(feature.benefits.length).toBeLessThanOrEqual(5);
    }
  });

  it('featured features count is ≤6', () => {
    const featuredCount = features.filter((f) => f.featured).length;
    expect(featuredCount).toBeLessThanOrEqual(6);
  });

  it('covers all 5 categories', () => {
    const categories = new Set(features.map((f) => f.category));
    const allCategories = Object.keys(CATEGORY_LABELS) as FeatureCategory[];
    for (const cat of allCategories) {
      expect(categories.has(cat)).toBe(true);
    }
  });

  it('media items with screenshot have alt text', () => {
    for (const feature of features) {
      if (feature.media?.screenshot) {
        expect(feature.media.alt).toBeTruthy();
      }
    }
  });
});
```

**What these tests validate:**
- Slug uniqueness — prevents routing collisions
- Related feature references — prevents broken cross-links on feature pages
- Tagline length ≤80 chars — enforces card layout consistency
- Description length 120-160 chars — enforces SEO meta description quality
- Benefits count 3-5 — enforces feature page content density
- Featured count ≤6 — enforces homepage grid constraint
- Category coverage — ensures no empty category tabs
- Media accessibility — ensures alt text on screenshots

**Run with:** `pnpm vitest run apps/site/src/layers/features/marketing/lib/__tests__/features.test.ts`

**Acceptance Criteria:**
- [ ] All 8 tests pass
- [ ] Tests catch violations if feature data is modified incorrectly (e.g., adding a 7th featured feature)
- [ ] No imports outside the marketing lib directory

Write component tests for the `FeatureCard` component covering rendering and all status variants.

**File to create:** `apps/site/src/layers/features/marketing/ui/__tests__/FeatureCard.test.tsx`

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect } from 'vitest';
import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import { FeatureCard } from '../FeatureCard';
import type { Feature } from '../../lib/features';

const mockFeature: Feature = {
  slug: 'test-feature',
  name: 'Test Feature',
  category: 'core',
  tagline: 'A tagline that explains the benefit',
  description: 'A description of the feature that is 120-160 chars for testing purposes here.',
  status: 'ga',
  benefits: ['First benefit here', 'Second benefit here', 'Third benefit here'],
};

describe('FeatureCard', () => {
  it('renders feature name and tagline', () => {
    render(<FeatureCard feature={mockFeature} />);
    expect(screen.getByText('Test Feature')).toBeInTheDocument();
    expect(screen.getByText('A tagline that explains the benefit')).toBeInTheDocument();
  });

  it('links to the correct feature slug', () => {
    render(<FeatureCard feature={mockFeature} />);
    const link = screen.getByRole('link');
    expect(link).toHaveAttribute('href', '/features/test-feature');
  });

  it('renders category and status badges', () => {
    render(<FeatureCard feature={mockFeature} />);
    expect(screen.getByText('Core')).toBeInTheDocument();
    expect(screen.getByText('Available')).toBeInTheDocument();
  });

  it('renders beta badge for beta status', () => {
    render(<FeatureCard feature={{ ...mockFeature, status: 'beta' }} />);
    expect(screen.getByText('Beta')).toBeInTheDocument();
  });

  it('renders Coming Soon badge for coming-soon status', () => {
    render(<FeatureCard feature={{ ...mockFeature, status: 'coming-soon' }} />);
    expect(screen.getByText('Coming Soon')).toBeInTheDocument();
  });
});
```

**Note:** The `mockFeature` has 3 benefits to meet the minimum (3-5) requirement from the Feature interface constraints, even though benefits aren't rendered in the card. The `description` field must be populated even though it isn't displayed in the card, since it's a required field on the `Feature` type.

**Run with:** `pnpm vitest run apps/site/src/layers/features/marketing/ui/__tests__/FeatureCard.test.tsx`

**Acceptance Criteria:**
- [ ] All 5 tests pass
- [ ] Tests use `@vitest-environment jsdom` directive
- [ ] Tests import from relative paths (not barrel) for isolation
- [ ] Mock data satisfies the Feature type contract

Write component tests for the `FeatureCatalogSection` homepage teaser, verifying it only renders featured features.

**File to create:** `apps/site/src/layers/features/marketing/ui/__tests__/FeatureCatalogSection.test.tsx`

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi } from 'vitest';
import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import { FeatureCatalogSection } from '../FeatureCatalogSection';

// Mock the features module to control which features appear
vi.mock('../../lib/features', () => ({
  features: [
    { slug: 'f1', name: 'Feature One', category: 'core', tagline: 'Tagline 1',
      description: 'Desc 1', status: 'ga', featured: true, benefits: [] },
    { slug: 'f2', name: 'Feature Two', category: 'pulse', tagline: 'Tagline 2',
      description: 'Desc 2', status: 'ga', featured: true, benefits: [] },
    { slug: 'f3', name: 'Feature Three', category: 'relay', tagline: 'Tagline 3',
      description: 'Desc 3', status: 'ga', featured: false, benefits: [] },
  ],
  CATEGORY_LABELS: { core: 'Core', pulse: 'Pulse', relay: 'Relay', mesh: 'Mesh', console: 'Console' },
}));

describe('FeatureCatalogSection', () => {
  it('renders only featured features', () => {
    render(<FeatureCatalogSection />);
    expect(screen.getByText('Feature One')).toBeInTheDocument();
    expect(screen.getByText('Feature Two')).toBeInTheDocument();
    expect(screen.queryByText('Feature Three')).not.toBeInTheDocument();
  });

  it('renders View all features link to /features', () => {
    render(<FeatureCatalogSection />);
    const links = screen.getAllByRole('link', { name: /all features/i });
    expect(links.length).toBeGreaterThan(0);
    expect(links[0]).toHaveAttribute('href', '/features');
  });
});
```

**Key testing details:**
- The features module is mocked with `vi.mock()` to control which features appear in the test, avoiding dependency on the real data
- Feature Three has `featured: false` and should NOT appear
- Feature One and Two have `featured: true` and should appear
- The "All features" link exists in both desktop (hidden sm:flex) and mobile (sm:hidden) variants — `getAllByRole` captures both
- `CATEGORY_LABELS` must be included in the mock because `FeatureCard` imports it from the same module

**Run with:** `pnpm vitest run apps/site/src/layers/features/marketing/ui/__tests__/FeatureCatalogSection.test.tsx`

**Acceptance Criteria:**
- [ ] Both tests pass
- [ ] Tests use `@vitest-environment jsdom` directive
- [ ] Mock properly controls which features are rendered
- [ ] Non-featured features are confirmed absent with `queryByText`
